/// <reference path="./elements.d.ts" />
/// <reference path="./components.d.ts" />

interface FullSlotId {
  readonly component: string;
  readonly element: string;
  readonly slot: string;
}

interface SlotInstanceElement {
  readonly id: FullSlotId;
  getDisplayName(): Promise<string | null>;
  getChildren(): Promise<AnyElement[]>;
  append(child: AnyComponent): Promise<null>;
  prepend(child: AnyComponent): Promise<null>;
}

interface FullTextPropId {
  readonly component: string;
  readonly element: string;
  readonly prop: string;
}

type TextPropInsertTarget =
  | AnyElement
  | ElementPreset<AnyElement>
  | BuilderElement
  | string
  | AnyComponent;

interface TextPropElement {
  readonly id: FullTextPropId;
  readonly type: 'TextPropElement';
  getDisplayName(): Promise<string>;
  getChildren(): Promise<AnyElement[]>;
  append(target: TextPropInsertTarget): Promise<AnyElement>;
  prepend(target: TextPropInsertTarget): Promise<AnyElement>;
}

interface RichTextPropElement {
  readonly id: FullTextPropId;
  readonly type: 'RichTextPropElement';
  getDisplayName(): Promise<string>;
  getChildren(): Promise<AnyElement[]>;
  append(target: TextPropInsertTarget): Promise<AnyElement>;
  prepend(target: TextPropInsertTarget): Promise<AnyElement>;
}
